"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[367],{262:(D,B,i)=>{i.r(B),i.d(B,{data:()=>e});const e=JSON.parse('{"key":"v-40348295","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D1%81%D1%82%D1%80%D0%B8%D0%B6%D0%B0%D0%BA-%D0%BD%D0%B0%D0%B4%D1%83%D1%82%D0%B5%D0%BD%D0%BA%D0%BE-%D0%B3%D0%BE%D1%80%D0%B1%D0%BE%D1%80%D1%83%D0%BA%D0%BE%D0%B2-%D0%BF%D1%80%D0%B8%D1%85%D0%BE%D0%B4%D0%BD%D1%8E%D0%BA-%D0%BE%D0%BD%D1%82%D0%BE%D0%BB%D0%BE%D0%B3%D0%B8%D1%8F-%D0%B6%D0%B8%D0%B7%D0%BD%D0%B5%D0%B4%D0%B5%D1%8F%D1%82%D0%B5%D0%BB%D1%8C%D0%BD%D0%BE%D1%81%D1%82%D0%B8-%D0%B0%D0%BA%D0%B0%D0%B4%D0%B5%D0%BC%D0%B8%D0%BA%D0%B0.html","title":"Онтология жизнедеятельности академика Виктора Глушкова","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[{"level":2,"title":"Список использованных источников","slug":"список-использованных-источников","link":"#список-использованных-источников","children":[]}],"git":{"updatedTime":1731179119000},"filePathRelative":"глушковские-чтения/стрижак-надутенко-горборуков-приходнюк-онтология-жизнедеятельности-академика.md"}')},9882:(D,B,i)=>{i.r(B),i.d(B,{default:()=>n});var e=i(6252);const a=(0,e._)("h1",{id:"онтология-жизнедеятельности-академика-виктора-глушкова",tabindex:"-1"},[(0,e._)("a",{class:"header-anchor",href:"#онтология-жизнедеятельности-академика-виктора-глушкова","aria-hidden":"true"},"#"),(0,e.Uk)(" Онтология жизнедеятельности академика Виктора Глушкова")],-1),t=(0,e._)("p",null,"Стрижак О. Е., Надутенко М. В., Горборуков В. В., Приходнюк В. В., г. Киев. Перевод с украинского.",-1),p=(0,e.uE)('<p>Виктор Михайлович Глушков, как многогранная личность, возбуждала и возбуждает интерес к себе у широких кругов человеческого сообщества как при жизни, так и во время, когда его нет среди нас. Поэтому отражение глубины и широты его жизнедеятельности, особое для молодежи, новейших поколений исследователей научных горизонтов кибернетики, информатики, математики, искусственного интеллекта и т.д., всегда будет актуально. Прикосновение к мыслям великого кибернетика волнует каждого специалиста в этих научных областях.</p><p>Отражение жизнедеятельности личности вообще, и особенно такой как Глушков, является достаточно сложной задачей. Здесь нужно представить достаточно большое количество страниц его биографии; учителей; семью; направления научной деятельности; научные нарративы, вышедшие из-под его пера и многое другое. И самое главное — обеспечить их достаточно сильную глубинную связность независимо от формы их существования. Одним из таких инструментов, который способен эффективно реализовать агрегированный формат отображения жизнедеятельности такой личности как Виктор Глушков является онтология [1]. Она обеспечивает полномасштабную классификацию жизнедеятельности, постоянный сбор различных по направлениям фактов и событий из деятельности личности, выявление и фиксацию связей между этими фактами и событиями, представление личности в цельном образе и тому подобное.</p><p>Более того, онтология способна обеспечивать определение, формирование и отображение всех семантических полей, которые определяют жизнедеятельность личности. Такие семантические поля обеспечивают представление уровней позиционирования личности в современном научном пространстве. Они определенным образом задают научные ориентиры и многовекторность дальнейших исследований по различным направлениям, которые в свое время исследовал выдающийся ученый, такой как Виктор Глушков. На их основе возможно оценивание уровней достижений различных исследователей, которые еще только начинают свой личный путь в науке.</p><p>Онтология жизнедеятельности академика Глушкова была создана еще на 100-летний юбилей НАН Украины. При ее формировании был использован достаточно широкий спектр информации, характеризующий грани жизнедеятельности Виктора Глушкова. Фрагмент соответствующей онтологии представлен на рис. 1.</p><p>Как видим концепты онтологии, которые фиксируют определенные факты и события в его жизни представлены в формате онтологического графа (правая часть рисунка), и таксономической иерархии (левая часть рисунка). Фактически концепты онтологии отражают факты его научной деятельности, организационные способности его личности. В онтологию включен достаточно широкий информационный массив о его семье, учителях, учениках, научных изданиях, научных учреждениях, в которых реализовывались его проекты, идеи и гипотезы и т.п.</p><figure><img src="/images/глушковские-чтения/стрижак-надутенко-горборуков-приходнюк-онтология-жизнедеятельности-академика-1.png" alt="" tabindex="0"><figcaption></figcaption></figure><p>Рис. 1. Фрагмент онтологии жизнедеятельности Виктора Глушкова.</p><p>Сервисы онтологии реализуют иерархическую фильтрацию информации о жизнедеятельности. Это обеспечивается на основе определенных при ее реализации тематических классов и подклассов разного уровня. Так на рис. 2 представлен фрагмент тематических классов, которые классифицируют направления отображения информации о его жизнедеятельности.</p><figure><img src="/images/глушковские-чтения/стрижак-надутенко-горборуков-приходнюк-онтология-жизнедеятельности-академика-2.png" alt="" tabindex="0"><figcaption></figcaption></figure><p>Рис. 2. Фрагмент тематических классов первого и второго уровня представления информации относительно академика Глушкова</p><p>Отдельный формат отображения жизнедеятельности имеет онтологическая Т-ПРИЗМА, которая представлена на рис. 3. Она реализует семантическую свертку и агрегативное отображение произвольной информации о Глушкове. Каждая грань Т-ПРИЗМЫ может быть представлена различными классами концептов онтологии, которые характеризуют жизнедеятельность Глушкова. Топология семантической свертки Т-ПРИЗМА имеет формат вложенности типа «матрешка». Каждая грань, если она отражает сложный концепт, может реализует непрерывное топологическое преобразование в формат Т-ПРИЗМЫ, которая отражает концепты из таксономического многообразия класса, представленного гранью основной Т-ПРИЗМЫ.</p><figure><img src="/images/глушковские-чтения/стрижак-надутенко-горборуков-приходнюк-онтология-жизнедеятельности-академика-3.png" alt="" tabindex="0"><figcaption></figcaption></figure><p>Рис. 3. Т-ПРИЗМА</p><p>Еще один сервис, который обеспечивает онтология жизнедеятельности Глушкова, реализует ранжирование семантических полей результатов деятельности ученых относительно семантического поля, которое формируется на основе научных результатов исследований Виктора Глушкова. На его основе были выявлены ученики, лауреаты национального конкурса МАН, которые были приглашены с докладами на юбилейную Международную научно-практическую конференцию «ГЛУШКОВСКИЕ ЧТЕНИЯ» к 100-летию со дня рождения В. М. Глушкова.</p><p>Для этого было сформировано семантическое поле на основе лингво-семантического анализа монографии «Основы безбумажной информатики». Оно включило в себя более 22 000 концептов. Затем был реализован эквивалентный логико-семантический анализ научно-образовательных работ учеников — лауреатов национального конкурса МАН по предметным профилям: компьютерная инженерия; кибербезопасность; программная инженерия; системы и технологии искусственного интеллекта; интернет-технологии и вебдизайн; учебные, игровые программы и виртуальная реальность; информационно-телекоммуникационные системы и технологии; математика; прикладная математика; статистика. Из 80-ти лауреатов было отобрано 15 учеников по значениям их рейтингов в семантическом поле Глушкова (рис. 4).</p><figure><img src="/images/глушковские-чтения/стрижак-надутенко-горборуков-приходнюк-онтология-жизнедеятельности-академика-4.png" alt="" tabindex="0"><figcaption></figcaption></figure><p>Рис. 4. Рейтинг учеников-лауреатов национального конкурса МАН в семантическом поле Глушкова</p><h2 id="список-использованных-источников" tabindex="-1"><a class="header-anchor" href="#список-использованных-источников" aria-hidden="true">#</a> Список использованных источников</h2><ol><li>Информационно-обучающие ресурсы. Капсулы знаний: Коллективная монография // Довгий С. А., Стрижак А. Е., Величко В. Ю., и др. Киев: Институт одаренного ребенка. 2019. — 215 с.</li></ol>',19),r={},n=(0,i(3744).Z)(r,[["render",function(D,B){const i=(0,e.up)("RouterLink");return(0,e.wg)(),(0,e.iD)("div",null,[a,t,(0,e._)("p",null,[(0,e.Uk)("Из материалов конференции "),(0,e.Wm)(i,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,e.w5)((()=>[(0,e.Uk)("«Глушковские чтения»")])),_:1}),(0,e.Uk)(" 2023 года.")]),p])}]])}}]);